import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const y=JSON.parse('{"title":"鲁迅故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/lu-xun-residence.md","filePath":"history/lu-xun-residence.md","lastUpdated":1784712887000}'),n={name:"history/lu-xun-residence.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="鲁迅故居" tabindex="-1">鲁迅故居 <a class="header-anchor" href="#鲁迅故居" aria-label="Permalink to &quot;鲁迅故居&quot;">​</a></h1><blockquote><p>&quot;新文化运动的旗手，民族魂的栖息地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>鲁迅故居位于北京市西城区阜成门内西三条21号，是鲁迅先生1924年至1926年在北京居住的地方。这是一座典型的北京四合院，鲁迅在这里完成了《华盖集》《华盖集续编》《野草》等作品。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线阜成门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区阜成门内西三条21号</td></tr></tbody></table><h2 id="鲁迅简介" tabindex="-1">鲁迅简介 <a class="header-anchor" href="#鲁迅简介" aria-label="Permalink to &quot;鲁迅简介&quot;">​</a></h2><h3 id="生平" tabindex="-1">生平 <a class="header-anchor" href="#生平" aria-label="Permalink to &quot;生平&quot;">​</a></h3><p>鲁迅（1881-1936），原名周树人，字豫才，浙江绍兴人。中国现代文学的奠基人，伟大的文学家、思想家、革命家。</p><ul><li><strong>1881年</strong>：生于浙江绍兴</li><li><strong>1902年</strong>：留学日本</li><li><strong>1909年</strong>：回国任教</li><li><strong>1918年</strong>：发表《狂人日记》，首次使用&quot;鲁迅&quot;笔名</li><li><strong>1924年</strong>：购得阜成门内西三条21号</li><li><strong>1926年</strong>：离开北京南下</li><li><strong>1936年</strong>：病逝于上海</li></ul><h3 id="主要作品" tabindex="-1">主要作品 <a class="header-anchor" href="#主要作品" aria-label="Permalink to &quot;主要作品&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">作品</th><th style="text-align:center;">类型</th><th style="text-align:center;">发表时间</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《狂人日记》</strong></td><td style="text-align:center;">小说</td><td style="text-align:center;">1918年</td></tr><tr><td style="text-align:left;"><strong>《阿Q正传》</strong></td><td style="text-align:center;">小说</td><td style="text-align:center;">1921年</td></tr><tr><td style="text-align:left;"><strong>《呐喊》</strong></td><td style="text-align:center;">小说集</td><td style="text-align:center;">1923年</td></tr><tr><td style="text-align:left;"><strong>《彷徨》</strong></td><td style="text-align:center;">小说集</td><td style="text-align:center;">1926年</td></tr><tr><td style="text-align:left;"><strong>《野草》</strong></td><td style="text-align:center;">散文诗集</td><td style="text-align:center;">1927年</td></tr><tr><td style="text-align:left;"><strong>《朝花夕拾》</strong></td><td style="text-align:center;">散文集</td><td style="text-align:center;">1928年</td></tr></tbody></table><h2 id="故居建筑" tabindex="-1">故居建筑 <a class="header-anchor" href="#故居建筑" aria-label="Permalink to &quot;故居建筑&quot;">​</a></h2><h3 id="四合院" tabindex="-1">四合院 <a class="header-anchor" href="#四合院" aria-label="Permalink to &quot;四合院&quot;">​</a></h3><p>鲁迅故居是一座典型的北京小四合院，坐北朝南。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">约400平方米</td></tr><tr><td style="text-align:left;"><strong>建筑格局</strong></td><td style="text-align:left;">小型四合院</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">鲁迅卧室兼书房</td></tr><tr><td style="text-align:left;"><strong>南房</strong></td><td style="text-align:left;">会客室和藏书室</td></tr><tr><td style="text-align:left;"><strong>东西厢房</strong></td><td style="text-align:left;">厨房和杂物间</td></tr></tbody></table><h3 id="鲁迅手植白丁香" tabindex="-1">鲁迅手植白丁香 <a class="header-anchor" href="#鲁迅手植白丁香" aria-label="Permalink to &quot;鲁迅手植白丁香&quot;">​</a></h3><p>院内有一棵白丁香树，是鲁迅1924年手植，至今已有近百年历史。</p><h3 id="老虎尾巴" tabindex="-1">&quot;老虎尾巴&quot; <a class="header-anchor" href="#老虎尾巴" aria-label="Permalink to &quot;&quot;老虎尾巴&quot;&quot;">​</a></h3><p>正房后面接出一间平顶小屋，鲁迅称之为&quot;老虎尾巴&quot;，是他的书房和卧室。在这里，鲁迅完成了大量作品。</p><h2 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h2><p>故居内设有鲁迅生平展览，包括：</p><ul><li><strong>生平照片</strong>：鲁迅各个时期的照片</li><li><strong>手稿书信</strong>：鲁迅的手稿和书信</li><li><strong>生活用品</strong>：鲁迅使用过的物品</li><li><strong>藏书</strong>：鲁迅的藏书</li><li><strong>作品展示</strong>：鲁迅的作品和翻译作品</li></ul><h2 id="鲁迅在北京" tabindex="-1">鲁迅在北京 <a class="header-anchor" href="#鲁迅在北京" aria-label="Permalink to &quot;鲁迅在北京&quot;">​</a></h2><h3 id="北京岁月" tabindex="-1">北京岁月 <a class="header-anchor" href="#北京岁月" aria-label="Permalink to &quot;北京岁月&quot;">​</a></h3><p>鲁迅在北京生活了14年（1912-1926），这是他创作生涯的重要时期。</p><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">经历</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1912年</strong></td><td style="text-align:left;">任教育部部员</td></tr><tr><td style="text-align:left;"><strong>1918年</strong></td><td style="text-align:left;">发表《狂人日记》</td></tr><tr><td style="text-align:left;"><strong>1920年</strong></td><td style="text-align:left;">任北大讲师，讲授中国小说史</td></tr><tr><td style="text-align:left;"><strong>1923年</strong></td><td style="text-align:left;">与周作人决裂，搬出八道湾</td></tr><tr><td style="text-align:left;"><strong>1924年</strong></td><td style="text-align:left;">购得阜成门内西三条21号</td></tr><tr><td style="text-align:left;"><strong>1926年</strong></td><td style="text-align:left;">离开北京南下</td></tr></tbody></table><h3 id="创作高峰" tabindex="-1">创作高峰 <a class="header-anchor" href="#创作高峰" aria-label="Permalink to &quot;创作高峰&quot;">​</a></h3><p>在北京期间，鲁迅创作了大量作品，包括小说、散文、杂文等。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>故居参观（约30分钟-1小时）</strong>：</p><p>门楼 → 南房（会客室） → 院内（白丁香） → 正房（卧室） → &quot;老虎尾巴&quot;（书房） → 展览</p><p><strong>结合游览路线</strong>：</p><p>鲁迅故居 → 鲁迅博物馆 → 白塔寺 → 什刹海</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线阜成门站B口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">3路、13路、42路等阜成门内站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从西单步行约20分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费参观</strong>：免费参观</li><li><strong>保持安静</strong>：保持安静</li><li><strong>了解历史</strong>：了解鲁迅的生平事迹</li><li><strong>结合游览</strong>：可与鲁迅博物馆、白塔寺一起游览</li><li><strong>丁香季节</strong>：4月丁香花开，香气袭人</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">鲁迅博物馆</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">鲁迅生平展览</td></tr><tr><td style="text-align:left;">白塔寺</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">藏传佛教寺院</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京风情</td></tr><tr><td style="text-align:left;">阜成门商圈</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">商业区</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>鲁迅故居是鲁迅在北京的最后居所，是他创作生涯的重要场所。</p><p>鲁迅是中国现代文学的奠基人，他的作品深刻揭露了旧社会的黑暗，唤醒了民众的意识。参观鲁迅故居，可以了解这位伟大文学家的生平事迹和创作历程。</p><hr><p><strong>📍 地址</strong>：北京市西城区阜成门内西三条21号 <strong>📞 电话</strong>：010-66156850</p>',46)])])}const f=e(n,[["render",d]]);export{y as __pageData,f as default};
